// MARK: - Deep Link Parser

struct DeepLinkParser {
    
    private static let allowedHost = "myapp.com"
    private static let allowedScheme = "https"
    
    /// Parses a URL into a DeepLinkRoute with security validation
    static func parse(url: URL) -> DeepLinkRoute? {
        // SECURITY: Only allow HTTPS scheme to prevent downgrade attacks
        guard let scheme = url.scheme?.lowercased(), scheme == allowedScheme else {
            print("[DeepLink] Rejected: Invalid scheme. Only HTTPS is allowed.")
            return nil
        }
        
        // SECURITY: Validate the host matches our expected domain exactly
        guard let host = url.host?.lowercased(), host == allowedHost else {
            print("[DeepLink] Rejected: Invalid host. Expected \(allowedHost).")
            return nil
        }
        
        // SECURITY: Reject URLs with embedded credentials (user:password@host)
        guard url.user == nil, url.password == nil else {
            print("[DeepLink] Rejected: URL contains embedded credentials.")
            return nil
        }
        
        // SECURITY: Normalize path to prevent path traversal attacks
        let path = url.path
        guard !path.contains("..") else {
            print("[DeepLink] Rejected: Path traversal detected.")
            return nil
        }
        
        // SECURITY: Reject excessively long URLs
        guard url.absoluteString.count <= 2048 else {
            print("[DeepLink] Rejected: URL exceeds maximum allowed length.")
            return nil
        }
        
        // Parse path components (first element is empty string due to leading "/")
        let pathComponents = path.split(separator: "/").map(String.init)
        
        return matchRoute(from: pathComponents)
    }
    
    private static func matchRoute(from pathComponents: [String]) -> DeepLinkRoute? {
        guard !pathComponents.isEmpty else {
            return .unknown
        }
        
        switch pathComponents {
        case let components where components.count == 2 && components[0] == "profile":
            let userID = components[1]
            // SECURITY: Validate userID is alphanumeric to prevent injection
            guard isValidUserID(userID) else {
                print("[DeepLink] Rejected: Invalid user ID format.")
                return nil
            }
            return .profile(userID: userID)
            
        case let components where components.count == 2 && components[0] == "payment" && components[1] == "confirm":
            return .paymentConfirm
            
        case let components where components.count == 2 && components[0] == "admin" && components[1] == "settings":
            return .adminSettings
            
        default:
            print("[DeepLink] No matching route for path components: \(pathComponents)")
            return .unknown
        }
    }
    
    /// Validates that a user ID contains only safe characters (alphanumeric, hyphens, underscores)
    private static func isValidUserID(_ userID: String) -> Bool {
        let allowedCharacters = CharacterSet.alphanumerics.union(CharacterSet(charactersIn: "-_"))
        return !userID.isEmpty
            && userID.count <= 128
            && userID.unicodeScalars.allSatisfy { allowedCharacters.contains($0) }
    }
}

// MARK: - Navigation Coordinator

protocol DeepLinkNavigator: AnyObject {
    func navigateToProfile(userID: String)
    func navigateToPaymentConfirm()
    func navigateToAdminSettings()
    func navigateToNotFound()
}

class DeepLinkCoordinator {
    
    weak var navigator: DeepLinkNavigator?
    
    /// Whether the current user is authenticated
    var isAuthenticated: Bool = false
    
    /// Whether the current user has admin privileges
    var isAdmin: Bool = false
    
    func handleDeepLink(url: URL) -> Bool {
        guard let route = DeepLinkParser.parse(url: url) else {
            print("[DeepLink] URL rejected by parser: \(url.absoluteString)")
            return false
        }
        
        return navigate(to: route)
    }
    
    func navigate(to route: DeepLinkRoute) -> Bool {
        switch route {
        case .profile(let userID):
            // SECURITY: Require authentication for profile access
            guard isAuthenticated else {
                print("[DeepLink] Authentication required for profile route.")
                return false
            }
            navigator?.navigateToProfile(userID: userID)
            return true
            
        case .paymentConfirm:
            // SECURITY: Require authentication for payment operations
            guard isAuthenticated else {
                print("[DeepLink] Authentication required for payment route.")
                return false
            }
            navigator?.navigateToPaymentConfirm()
            return true
            
        case .adminSettings:
            // SECURITY: Require authentication AND admin privileges
            guard isAuthenticated else {
                print("[DeepLink] Authentication required for admin route.")
                return false
            }
            guard isAdmin else {
                print("[DeepLink] Admin privileges required for admin settings.")
                return false
            }
            navigator?.navigateToAdminSettings()
            return true
            
        case .unknown:
            navigator?.navigateToNotFound()
            return false
        }
    }
}

