class MainNavigationController: UINavigationController, DeepLinkNavigator {
    
    func navigateToProfile(userID: String) {
        let vc = ProfileViewController(userID: userID)
        pushOrPresent(vc)
    }
    
    func navigateToPaymentConfirm() {
        let vc = PaymentConfirmViewController()
        pushOrPresent(vc)
    }
    
    func navigateToAdminSettings() {
        let vc = AdminSettingsViewController()
        pushOrPresent(vc)
    }
    
    func navigateToNotFound() {
        let vc = NotFoundViewController()
        pushOrPresent(vc)
    }
    
    private func pushOrPresent(_ viewController: UIViewController) {
        DispatchQueue.main.async { [weak self] in
            guard let self = self else { return }
            // Pop to root before navigating to deep link destination
            self.popToRootViewController(animated: false)
            self.pushViewController(viewController, animated: true)
        }
    }
}

