    func scene(
        _ scene: UIScene,
        willConnectTo session: UISceneSession,
        options connectionOptions: UIScene.ConnectionOptions
    ) {
        guard let windowScene = scene as? UIWindowScene else { return }
        
        let rootVC = UIViewController()
        rootVC.view.backgroundColor = .systemBackground
        rootVC.title = "Home"
        
        let homeLabel = UILabel()
        homeLabel.text = "Welcome to MyApp"
        homeLabel.font = .systemFont(ofSize: 24, weight: .bold)
        homeLabel.textAlignment = .center
        homeLabel.translatesAutoresizingMaskIntoConstraints = false
        rootVC.view.addSubview(homeLabel)
        NSLayoutConstraint.activate([
            homeLabel.centerXAnchor.constraint(equalTo: rootVC.view.centerXAnchor),
            homeLabel.centerYAnchor.constraint(equalTo: rootVC.view.centerYAnchor)
        ])
        
        let navController = MainNavigationController(rootViewController: rootVC)
        mainNavigationController = navController
        
        deepLinkCoordinator.navigator = navController
        deepLinkCoordinator.isAuthenticated = true
        deepLinkCoordinator.isAdmin = true
        
        window = UIWindow(windowScene: windowScene)
        window?.rootViewController = navController
        window?.makeKeyAndVisible()
        
        // Handle universal links that launched the app (cold start)
        if let userActivity = connectionOptions.userActivities.first(where: {
            $0.activityType == NSUserActivityTypeBrowsingWeb
        }) {
            handleUserActivity(userActivity)
        }
    }
    
    func scene(_ scene: UIScene, continue userActivity: NSUserActivity) {
        handleUserActivity(userActivity)
    }
    
    private func handleUserActivity(_ userActivity: NSUserActivity) {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb else {
            print("[DeepLink] Rejected: Activity type is not browsing web.")
            return
        }
        
        guard let url = userActivity.webpageURL else {
            print("[DeepLink] Rejected: No webpage URL in user activity.")
            return
        }
        
        print("[DeepLink] Handling universal link: \(url.absoluteString)")
        
        _ = deepLinkCoordinator.handleDeepLink(url: url)
    }
